(ns clojure.core-meta)

;; Existing keys win: a var's own meta (a defn-attached :arglists) is
;; preserved; only the missing keys are filled from the oracle table.
(def ^:private fill (fn [m mm] (merge mm m)))

(when-let [v (resolve (quote clojure.core/*agent*))] (alter-meta! v fill {:doc "The agent currently running an action on this thread, else nil"}))
(when-let [v (resolve (quote clojure.core/*assert*))] (alter-meta! v fill {:doc "When set to logical false, 'assert' will omit assertion checks in\n  compiled code. Defaults to true."}))
(when-let [v (resolve (quote clojure.core/*clojure-version*))] (alter-meta! v fill {:doc "The version info for Clojure core, as a map containing :major :minor \n  :incremental and :qualifier keys. Feature releases may increment \n  :minor and/or :major, bugfix releases will increment :incremental. \n  Possible values of :qualifier include \"GA\", \"SNAPSHOT\", \"RC-x\" \"BETA-x\""}))
(when-let [v (resolve (quote clojure.core/*command-line-args*))] (alter-meta! v fill {:doc "A sequence of the supplied command line arguments, or nil if\n  none were supplied"}))
(when-let [v (resolve (quote clojure.core/*data-readers*))] (alter-meta! v fill {:doc "Map from reader tag symbols to data reader Vars.\n\n  When Clojure starts, it searches for files named 'data_readers.clj'\n  and 'data_readers.cljc' at the root of the classpath. Each such file\n  must contain a literal map of symbols, like this:\n\n      {foo/bar my.project.foo/bar\n       foo/baz my.project/baz}\n\n  The first symbol in each pair is a tag that will be recognized by\n  the Clojure reader. The second symbol in the pair is the\n  fully-qualified name of a Var which will be invoked by the reader to\n  parse the form following the tag. For example, given the\n  data_readers.clj file above, the Clojure reader would parse this\n  form:\n\n      #foo/bar [1 2 3]\n\n  by invoking the Var #'my.project.foo/bar on the vector [1 2 3]. The\n  data reader function is invoked on the form AFTER it has been read\n  as a normal Clojure data structure by the reader.\n\n  Reader tags without namespace qualifiers are reserved for\n  Clojure. Default reader tags are defined in\n  clojure.core/default-data-readers but may be overridden in\n  data_readers.clj, data_readers.cljc, or by rebinding this Var."}))
(when-let [v (resolve (quote clojure.core/*default-data-reader-fn*))] (alter-meta! v fill {:doc "When no data reader is found for a tag and *default-data-reader-fn*\n  is non-nil, it will be called with two arguments,\n  the tag and the value.  If *default-data-reader-fn* is nil (the\n  default), an exception will be thrown for the unknown tag."}))
(when-let [v (resolve (quote clojure.core/*err*))] (alter-meta! v fill {:doc "A java.io.Writer object representing standard error for print operations.\n\n  Defaults to System/err, wrapped in a PrintWriter"}))
(when-let [v (resolve (quote clojure.core/*flush-on-newline*))] (alter-meta! v fill {:doc "When set to true, output will be flushed whenever a newline is printed.\n\n  Defaults to true."}))
(when-let [v (resolve (quote clojure.core/*in*))] (alter-meta! v fill {:doc "A java.io.Reader object representing standard input for read operations.\n\n  Defaults to System/in, wrapped in a LineNumberingPushbackReader"}))
(when-let [v (resolve (quote clojure.core/*ns*))] (alter-meta! v fill {:doc "A clojure.lang.Namespace object representing the current namespace."}))
(when-let [v (resolve (quote clojure.core/*out*))] (alter-meta! v fill {:doc "A java.io.Writer object representing standard output for print operations.\n\n  Defaults to System/out, wrapped in an OutputStreamWriter"}))
(when-let [v (resolve (quote clojure.core/*print-dup*))] (alter-meta! v fill {:doc "When set to logical true, objects will be printed in a way that preserves\n  their type when read in later.\n\n  Defaults to false."}))
(when-let [v (resolve (quote clojure.core/*print-length*))] (alter-meta! v fill {:doc "*print-length* controls how many items of each collection the\n  printer will print. If it is bound to logical false, there is no\n  limit. Otherwise, it must be bound to an integer indicating the maximum\n  number of items of each collection to print. If a collection contains\n  more items, the printer will print items up to the limit followed by\n  '...' to represent the remaining items. The root binding is nil\n  indicating no limit."}))
(when-let [v (resolve (quote clojure.core/*print-level*))] (alter-meta! v fill {:doc "*print-level* controls how many levels deep the printer will\n  print nested objects. If it is bound to logical false, there is no\n  limit. Otherwise, it must be bound to an integer indicating the maximum\n  level to print. Each argument to print is at level 0; if an argument is a\n  collection, its items are at level 1; and so on. If an object is a\n  collection and is at a level greater than or equal to the value bound to\n  *print-level*, the printer prints '#' to represent it. The root binding\n  is nil indicating no limit."}))
(when-let [v (resolve (quote clojure.core/*print-meta*))] (alter-meta! v fill {:doc "If set to logical true, when printing an object, its metadata will also\n  be printed in a form that can be read back by the reader.\n\n  Defaults to false."}))
(when-let [v (resolve (quote clojure.core/*print-namespace-maps*))] (alter-meta! v fill {:doc "*print-namespace-maps* controls whether the printer will print\n  namespace map literal syntax. It defaults to false, but the REPL binds\n  to true."}))
(when-let [v (resolve (quote clojure.core/*print-readably*))] (alter-meta! v fill {:doc "When set to logical false, strings and characters will be printed with\n  non-alphanumeric characters converted to the appropriate escape sequences.\n\n  Defaults to true"}))
(when-let [v (resolve (quote clojure.core/*unchecked-math*))] (alter-meta! v fill {:doc "While bound to true, compilations of +, -, *, inc, dec and the\n  coercions will be done without overflow checks. While bound\n  to :warn-on-boxed, same behavior as true, and a warning is emitted\n  when compilation uses boxed math. Default: false."}))
(when-let [v (resolve (quote clojure.core/*warn-on-reflection*))] (alter-meta! v fill {:doc "When set to true, the compiler will emit warnings when reflection is\n  needed to resolve Java method calls or field accesses.\n\n  Defaults to false."}))
(when-let [v (resolve (quote clojure.core/->Eduction))] (alter-meta! v fill {:arglists (quote ([xform coll])), :doc "Positional factory function for class clojure.core.Eduction."}))
(when-let [v (resolve (quote clojure.core/Throwable->map))] (alter-meta! v fill {:arglists (quote ([o])), :doc "Constructs a data representation for a Throwable with keys:\n    :cause - root cause message\n    :phase - error phase\n    :via - cause chain, with cause keys:\n             :type - exception class symbol\n             :message - exception message\n             :data - ex-data\n             :at - top stack element\n    :trace - root cause stack elements"}))
(when-let [v (resolve (quote clojure.core/add-tap))] (alter-meta! v fill {:arglists (quote ([f])), :doc "adds f, a fn of one argument, to the tap set. This function will be called with anything sent via tap>.\n  This function may (briefly) block (e.g. for streams), and will never impede calls to tap>,\n  but blocking indefinitely may cause tap values to be dropped.\n  Remember f in order to remove-tap"}))
(when-let [v (resolve (quote clojure.core/agent-errors))] (alter-meta! v fill {:arglists (quote ([a])), :doc "DEPRECATED: Use 'agent-error' instead.\n  Returns a sequence of the exceptions thrown during asynchronous\n  actions of the agent."}))
(when-let [v (resolve (quote clojure.core/alter-meta!))] (alter-meta! v fill {:arglists (quote ([iref f & args])), :doc "Atomically sets the metadata for a namespace/var/ref/agent/atom to be:\n\n  (apply f its-current-meta args)\n\n  f must be free of side-effects"}))
(when-let [v (resolve (quote clojure.core/amap))] (alter-meta! v fill {:arglists (quote ([a idx ret expr])), :doc "Maps an expression across an array a, using an index named idx, and\n  return value named ret, initialized to a clone of a, then setting \n  each element of ret to the evaluation of expr, returning the new \n  array ret."}))
(when-let [v (resolve (quote clojure.core/ancestors))] (alter-meta! v fill {:arglists (quote ([tag] [h tag])), :doc "Returns the immediate and indirect parents of tag, either via a Java type\n  inheritance relationship or a relationship established via derive. h\n  must be a hierarchy obtained from make-hierarchy, if not supplied\n  defaults to the global hierarchy"}))
(when-let [v (resolve (quote clojure.core/any?))] (alter-meta! v fill {:arglists (quote ([x])), :doc "Returns true given any argument."}))
(when-let [v (resolve (quote clojure.core/areduce))] (alter-meta! v fill {:arglists (quote ([a idx ret init expr])), :doc "Reduces an expression across an array a, using an index named idx,\n  and return value named ret, initialized to init, setting ret to the \n  evaluation of expr at each step, returning ret."}))
(when-let [v (resolve (quote clojure.core/aset-boolean))] (alter-meta! v fill {:arglists (quote ([array idx val] [array idx idx2 & idxv])), :doc "Sets the value at the index/indices. Works on arrays of boolean. Returns val."}))
