(when-let [v (resolve (quote clojure.core/aset-double))] (alter-meta! v fill {:arglists (quote ([array idx val] [array idx idx2 & idxv])), :doc "Sets the value at the index/indices. Works on arrays of double. Returns val."}))
(when-let [v (resolve (quote clojure.core/aset-float))] (alter-meta! v fill {:arglists (quote ([array idx val] [array idx idx2 & idxv])), :doc "Sets the value at the index/indices. Works on arrays of float. Returns val."}))
(when-let [v (resolve (quote clojure.core/aset-int))] (alter-meta! v fill {:arglists (quote ([array idx val] [array idx idx2 & idxv])), :doc "Sets the value at the index/indices. Works on arrays of int. Returns val."}))
(when-let [v (resolve (quote clojure.core/aset-long))] (alter-meta! v fill {:arglists (quote ([array idx val] [array idx idx2 & idxv])), :doc "Sets the value at the index/indices. Works on arrays of long. Returns val."}))
