(when-let [v (resolve (quote clojure.core/distinct?))] (alter-meta! v fill {:arglists (quote ([x] [x y] [x y & more])), :doc "Returns true if no two of the arguments are ="}))
(when-let [v (resolve (quote clojure.core/doall))] (alter-meta! v fill {:arglists (quote ([coll] [n coll])), :doc "When lazy sequences are produced via functions that have side\n  effects, any effects other than those needed to produce the first\n  element in the seq do not occur until the seq is consumed. doall can\n  be used to force any effects. Walks through the successive nexts of\n  the seq, retains the head and returns it, thus causing the entire\n  seq to reside in memory at one time."}))
